%% 4.8 limpiar todas las variables usadas
clear t ut simOut tt yy yint y0 y0ss SP u

t = (0:0.1:9.9)';          % 100 puntos
y0 = zeros(length(t), 7);  % matriz de respuestas

for i = 1:7
    u = i * ones(size(t));
    ut = [t u];

    % Simulacion (una sola salida)
    simOut = sim('ejemplo2', 'StopTime', '9.9', 'ExternalInput', 'ut');

    % Tomar tiempo y salida principal
    tt = simOut.tout;
    yy = simOut.yout;  

    % A columna e interpolar
    tt = tt(:);
    yy = yy(:);
    yint = interp1(tt, yy, t, 'linear', 'extrap');

    y0(:, i) = yint;
end

% Estado estable y sobrepaso
y0ss = y0(end, :);
SP = 100 * (max(y0, [], 1) - y0ss) ./ y0ss;

% Grafica unica
figure %[output:9114e6cc]
plot(t, y0, 'LineWidth', 1.2) %[output:9114e6cc]
grid on %[output:9114e6cc]
xlabel('Tiempo [s]') %[output:9114e6cc]
ylabel('Salida y(t)') %[output:9114e6cc]
title('Respuestas para u = 1..7') %[output:9114e6cc]
%[text] ![](text:image:7f94)
%[text] `yss =` 
%[text]  `1.0000    2.0000    3.0001    4.0000    4.9998    5.9987    6.9966`
%[text] `SP (%) =` 
%[text]  `37.4352   34.3390   31.2125   29.2859   29.4790   30.6291   31.9416`
legend('u=1','u=2','u=3','u=4','u=5','u=6','u=7','Location','best') %[output:9114e6cc]

disp('yss = ') %[output:6563e93a]
disp(y0ss) %[output:6ebca0a2]
disp('SP (%) = ') %[output:7b01fe5f]
disp(SP) %[output:9d7c42ee]

